10	inline void bzero(byte_ptr pointer, int size) {
11	  cb_assert(size >= 0 && "bzero: negative size");
12	  if (size == 0) return;
13	  cb_assert(pointer && "bzero: null pointer");
14	  memset(pointer, 0, static_cast<size_t>(size));
