17	inline void secure_bzero(byte_ptr pointer, int size) {
18	  if (size <= 0) return;
19	  cb_assert(pointer && "secure_bzero: null pointer");
20	#if defined(__STDC_LIB_EXT1__)
21	  // `memset_s` is guaranteed to perform the memory write and not be optimized away.
22	  (void)memset_s(pointer, static_cast<rsize_t>(size), 0, static_cast<rsize_t>(size));
23	#else
24	  // Best-effort fallback that compilers cannot elide.
25	  volatile byte_t* p = pointer;
26	  for (int i = 0; i < size; i++) p[i] = 0;
27	#endif
28	}
