276	template <typename T>
277	error_t convert(T& dst, mem_t src) {
278	  if (src.size < 0 || (src.size && !src.data)) return coinbase::error(E_BADARG);
279	  converter_t converter(src);
280	  converter.convert(dst);
281	  return converter.get_rv();
282	}
