136	error_t base_pke_rsa_ek_from_modulus(mem_t modulus, buf_t& out_ek) {
137	  if (const error_t rv = coinbase::api::detail::validate_mem_arg_max_size(modulus, "modulus",
138	                                                                          coinbase::api::detail::MAX_OPAQUE_BLOB_SIZE))
139	    return rv;
140	
141	  constexpr int kExpectedModulusBytes = coinbase::crypto::RSA_KEY_LENGTH / 8;
142	  if (modulus.size != kExpectedModulusBytes)
143	    return coinbase::error(E_BADARG, "modulus must be exactly 256 bytes (RSA-2048)");
144	
145	  constexpr unsigned long kDefaultExponent = 65537;
146	
147	  BIGNUM* n_bn = BN_bin2bn(modulus.data, modulus.size, nullptr);
148	  if (!n_bn) return coinbase::error(E_GENERAL, "BN_bin2bn(modulus) failed");
149	
150	  if (BN_is_zero(n_bn)) {
151	    BN_free(n_bn);
152	    return coinbase::error(E_BADARG, "modulus must not be zero");
153	  }
154	
155	  BIGNUM* e_bn = BN_new();
156	  if (!e_bn) {
157	    BN_free(n_bn);
158	    return coinbase::error(E_GENERAL, "BN_new(e) failed");
159	  }
160	  BN_set_word(e_bn, kDefaultExponent);
161	
162	  coinbase::crypto::rsa_pub_key_t pk;
163	  pk.set(n_bn, e_bn);
164	  BN_free(n_bn);
165	  BN_free(e_bn);
166	
167	  base_pke_ek_blob_v1_t ek_blob;
168	  ek_blob.key_type = static_cast<uint32_t>(base_pke_key_type_v1::rsa_oaep_2048);
169	  ek_blob.rsa_ek = std::move(pk);
170	
171	  out_ek = coinbase::convert(ek_blob);
172	  return SUCCESS;
